#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* weights = (int*)malloc(N * sizeof(int));
        int* costs = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &weights[i], &costs[i]);
        }
        int M = 0;
        for (int i = 0; i < N; i++) {
            M += weights[i];
        }
        int* dp = (int*)malloc((M + 1) * sizeof(int));
        for (int i = 0; i <= M; i++) {
            dp[i] = 0;
        }
        for (int i = 0; i < N; i++) {
            for (int j = M; j >= weights[i]; j--) {
                dp[j] = (dp[j] > dp[j - weights[i]] + costs[i]) ? dp[j] : dp[j - weights[i]] + costs[i];
            }
        }
        for (int i = 1; i <= M; i++) {
            printf("%d ", dp[i]);
        }
        printf("\n");
        free(weights);
        free(costs);
        free(dp);
    }
    return 0;
}

