import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.StringTokenizer;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine());
            int[] weights = new int[N];
            int[] costs = new int[N];
            for (int i = 0; i < N; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                weights[i] = Integer.parseInt(st.nextToken());
                costs[i] = Integer.parseInt(st.nextToken());
            }
            int M = 0;
            for (int i = 0; i < N; i++) {
                M += weights[i];
            }
            int[] dp = new int[M + 1];
            for (int i = 0; i < N; i++) {
                for (int j = M; j >= weights[i]; j--) {
                    dp[j] = Math.max(dp[j], dp[j - weights[i]] + costs[i]);
                }
            }
            for (int i = 1; i <= M; i++) {
                System.out.print(dp[i] + " ");
            }
            System.out.println();
        }
    }
}

code.JavaScript:
const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const T = parseInt(input[i++]);
for (let t = 0; t < T; t++) {
    const N = parseInt(input[i++]);
    const weights = [];
    const costs = [];
    for (let j = 0; j < N; j++) {
        const [w, c] = input[i++].split(' ').map(Number);
        weights.push(w);
        costs.push(c);
    }
    const M = weights.reduce((a, b) => a + b, 0);
    const dp = new Array(M + 1).fill(0);
    for (let j = 0; j < N; j++) {
        for (let k = M; k >= weights[j]; k--) {
            dp[k] = Math.max(dp[k], dp[k - weights[j]] + costs[j]);
        }
    }
    console.log(dp.slice(1).join(' '));
}

